const rows = $input.all().map(item => item.json);
const byRow = {};
rows.forEach(r => byRow[r.row_number] = r);

const colMap = {A:1,B:2,C:3,D:4,E:5,F:6,G:7,H:8,I:9,J:10,K:11,L:12,M:13,N:14,O:15,P:16,Q:17,R:18,S:19,T:20,U:21,V:22,W:23,X:24,Y:25,Z:26,AA:27,AB:28,AC:29,AD:30,AE:31,AF:32,AG:33};
const col = (rowNum, letter) => {
  const r = byRow[rowNum];
  if (!r) return null;
  return r['col_' + colMap[letter]] ?? null;
};

// Overview (B=label, C=value)
const overview = {};
for (let rn = 11; rn <= 15; rn++) {
  const label = col(rn, 'B');
  if (label) overview[label] = col(rn, 'C');
}

// Income by Category (E-I)
const incomeByCategory = [];
for (let rn = 12; rn <= 18; rn++) {
  const category = col(rn, 'E');
  if (!category) continue;
  incomeByCategory.push({
    category, amount: col(rn,'F'), plannedAllocation: col(rn,'G'),
    actualAllocation: col(rn,'H'), status: col(rn,'I')
  });
}

// Expense by Category (K-O), pisahkan baris Total
const expenseByCategory = [];
let expenseTotal = null;
for (let rn = 12; rn <= 30; rn++) {
  const category = col(rn, 'K');
  if (!category) continue;
  const entry = { category, actual: col(rn,'L'), budgetPlanned: col(rn,'M'), remaining: col(rn,'N'), status: col(rn,'O') };
  category === 'Total' ? expenseTotal = entry : expenseByCategory.push(entry);
}

// Saving & Assets (Q-V)
const savingAssets = [];
for (let rn = 12; rn <= 15; rn++) {
  const category = col(rn, 'Q');
  if (!category) continue;
  savingAssets.push({
    category, current: col(rn,'R'), saved: col(rn,'S'),
    plan: col(rn,'T'), progressPct: col(rn,'U'), vehicle: col(rn,'V')
  });
}

// Budget Flow (X-AA), pisahkan baris Total
const budgetFlow = [];
let budgetFlowTotal = null;
for (let rn = 12; rn <= 30; rn++) {
  const source = col(rn, 'X');
  if (!source) continue;
  const entry = { source, in: col(rn,'Y'), out: col(rn,'Z'), net: col(rn,'AA') };
  source === 'Total' ? budgetFlowTotal = entry : budgetFlow.push(entry);
}

// Balance per Source (AC-AF), pisahkan baris Total
const balancePerSource = [];
let balanceTotal = null;
for (let rn = 12; rn <= 30; rn++) {
  const source = col(rn, 'AC');
  if (!source) continue;
  const entry = { source, opening: col(rn,'AD'), netMovement: col(rn,'AE'), closing: col(rn,'AF') };
  source === 'Total' ? balanceTotal = entry : balancePerSource.push(entry);
}

const structuredData = {
  overview, incomeByCategory, expenseByCategory, expenseTotal,
  savingAssets, budgetFlow, budgetFlowTotal, balancePerSource, balanceTotal
};

return {
  json: {
    laporan_data: JSON.stringify(structuredData, null, 2),
    original_question: $('Switch').item.json.message.text,
    chat_id: $('Switch').item.json.message.chat.id
  }
};

let answer = $json.output[0].content[0].text;

answer = answer
  .replace(/\*\*(.+?)\*\*/g, '<b>$1</b>')
  .replace(/#{1,6}\s*(.+)/g, '<b>$1</b>')
  .replace(/^-\s+/gm, '📌 ');

const chatId = $('Switch').item.json.message.chat.id;

return {
  json: {
    chat_id: chatId,
    message_text: answer
  }
};

const msg = $json.message;
let jenisPesan = "tidak dikenal";

if (msg.sticker) jenisPesan = "stiker";
else if (msg.voice) jenisPesan = "pesan suara";
else if (msg.video_note) jenisPesan = "video bulat";
else if (msg.video) jenisPesan = "video";
else if (msg.audio) jenisPesan = "file audio";
else if (msg.document) jenisPesan = "dokumen";
else if (msg.location) jenisPesan = "lokasi";
else if (msg.contact) jenisPesan = "kontak";
else if (msg.poll) jenisPesan = "polling";
else if (msg.animation) jenisPesan = "GIF/animasi";

const message_text = `🤔 <b>Format Belum Didukung</b>\n\nMaaf, saya belum bisa memproses ${jenisPesan}.\n\nSaat ini saya hanya bisa membaca:\n📝 Teks (untuk catat transaksi atau tanya laporan)\n📸 Foto struk belanja (dengan caption sumber dana)`;

return {
  json: {
    chat_id: msg.chat.id,
    message_text: message_text
  }
};

const rows = $input.all().map(item => item.json);
const originalMessage = $('Telegram Trigger').item.json.message;
const incomingChatId = originalMessage.chat.id;

const matchedUser = rows.find(row => String(row.chat_id) === String(incomingChatId));

let statusUser = "baru";
if (matchedUser) {
  statusUser = matchedUser.status;
}

return {
  json: {
    status_user: statusUser,
    spreadsheet_id: matchedUser ? matchedUser.spreadsheet_id : null,
    nama: matchedUser ? matchedUser.nama : null,
    chat_id: incomingChatId,
    email: matchedUser ? matchedUser.email : null,
    message: originalMessage
  }
};

const message = `👋 <b>Selamat datang di Nexus Keuangan!</b>

Untuk mulai, saya perlu menyiapkan spreadsheet pribadi kamu.

Kirim alamat <b>Gmail</b> kamu ya, nanti spreadsheet-nya saya buatkan dan langsung jadi milikmu.`;

return {
