};

const originalMessage = $json.message;
const text = (originalMessage.text || '').trim();
const chatId = $json.chat_id;
const nama = originalMessage.from.first_name;

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const isValidEmail = emailRegex.test(text);
const isGmail = /@gmail\.com$/i.test(text);

let errorReason = null;
if (!text) errorReason = "bukan_teks";
else if (!isValidEmail || !isGmail) errorReason = "format_salah";

return {
  json: {
    email_valid: !errorReason,
    error_reason: errorReason,
    email: text,
    chat_id: chatId,
    nama: nama
  }
};

